DROP TABLE IF EXISTS `w_stat_game`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `w_stat_game` (
  `id` int NOT NULL AUTO_INCREMENT,
  `date_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `user_id` int NOT NULL,
  `balance` decimal(16,2) NOT NULL DEFAULT '0.00',
  `bet` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `win` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `game` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '',
  `in_game` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `in_jpg` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `in_profit` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `denomination` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `slots_bank` decimal(20,4) DEFAULT '0.0000',
  `bonus_bank` decimal(20,4) DEFAULT '0.0000',
  `fish_bank` decimal(20,4) DEFAULT '0.0000',
  `table_bank` decimal(20,4) DEFAULT '0.0000',
  `little_bank` decimal(20,4) DEFAULT '0.0000',
  `total_bank` decimal(20,4) DEFAULT '0.0000',
  `shop_id` int NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `user_id` (`user_id`) USING BTREE,
  KEY `game_id` (`game`) USING BTREE,
  KEY `date_time` (`date_time`) USING BTREE,
  KEY `shop_id` (`shop_id`),
  KEY `bet` (`bet`),
  KEY `balance` (`balance`),
  KEY `win` (`win`),
  KEY `in_profit` (`in_profit`)
) ENGINE=MyISAM AUTO_INCREMENT=20694 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC;
