CREATE TABLE `w_statistics` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `user_id` int NOT NULL,
  `payeer_id` int DEFAULT NULL,
  `system` enum('user','shop','bank','jpg','refund','happyhour','pincode','handpay','interkassa','coinbase','btcpayserver','invite','progress','tournament','daily_entry','welcome_bonus','sms_bonus','wheelfortune') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `old` decimal(20,4) NOT NULL,
  `sum` decimal(20,4) NOT NULL,
  `sum2` decimal(20,4) DEFAULT NULL,
  `hh_multiplier` int NOT NULL DEFAULT '1',
  `type` enum('add','out') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'add',
  `item_id` varchar(55) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` int NOT NULL DEFAULT '1',
  `ip_address` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `user_agent` varchar(550) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `country` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `city` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `os` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `device` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `browser` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `shop_id` int NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT '0000-00-00 00:00:00',
  PRIMARY KEY (`id`),
  KEY `system` (`system`),
  KEY `shop_id` (`shop_id`)
) ENGINE=MyISAM AUTO_INCREMENT=518 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC;
