/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `w_users` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `email` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '',
  `username` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `password` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `parent_id` int NOT NULL DEFAULT '0',
  `inviter_id` int NOT NULL DEFAULT '0',
  `first_name` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `last_name` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phone` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phone_verified` int NOT NULL DEFAULT '0',
  `rating` int NOT NULL DEFAULT '0',
  `avatar` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `address` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `role_id` int unsigned NOT NULL,
  `shop_id` int NOT NULL DEFAULT '0',
  `birthday` date DEFAULT NULL,
  `balance` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `tournaments` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `happyhours` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `refunds` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `progress` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `daily_entries` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `invite` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `welcomebonus` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `smsbonus` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `wheelfortune` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `count_balance` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `count_tournaments` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `count_happyhours` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `count_refunds` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `count_progress` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `count_daily_entries` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `count_invite` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `count_welcomebonus` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `count_smsbonus` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `count_wheelfortune` decimal(20,4) NOT NULL DEFAULT '0.0000',
  `total_in` float NOT NULL DEFAULT '0',
  `total_out` float NOT NULL DEFAULT '0',
  `last_login` timestamp NULL DEFAULT NULL,
  `confirmation_token` varchar(60) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `sms_token` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `sms_token_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_blocked` int NOT NULL DEFAULT '0',
  `is_demo_agent` int NOT NULL DEFAULT '0',
  `agreed` int NOT NULL DEFAULT '0',
  `free_demo` int NOT NULL DEFAULT '0',
  `remember_token` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `api_token` text COLLATE utf8mb4_unicode_ci,
  `auth_token` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `google2fa_enable` int NOT NULL DEFAULT '0',
  `google2fa_secret` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `language` varchar(55) COLLATE utf8mb4_unicode_ci DEFAULT 'en',
  `session` mediumtext COLLATE utf8mb4_unicode_ci,
  `last_online` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `last_bid` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `last_progress` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `last_daily_entry` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `last_wheelfortune` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `users_created_at_index` (`created_at`),
  KEY `users_username_index` (`username`),
  KEY `users_status_index` (`status`),
  KEY `shop_id` (`shop_id`),
  KEY `role_id` (`role_id`),
  KEY `parent_id` (`parent_id`)
) ENGINE=InnoDB AUTO_INCREMENT=202 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC;
